// ---------------------------------------------------------------------------
// Derived lookups
// ---------------------------------------------------------------------------

/**
 * O(1) lookup by id. Built once at module load. The canvas theme reads from
 * this for the `topLeft` icon slot's accessor — `customData.kind` is the
 * `id`, and the slot resolves the brand color and paths in one lookup.
 *
 * Returns `undefined` for unknown ids (a stale `customData.kind` from a
 * platform that was renamed / removed, or an arbitrary string the agent
 * authored). The canvas renderer treats unknown icon names as "render
 * nothing," so a node with `customData.kind: "made-up"` paints with no
 * icon and no error — exactly the v1 contract.
 */
export const PLATFORM_BY_ID: Record<string, Platform> = Object.fromEntries(
  PLATFORMS.map((p) => [p.id, p]),
);

/**
 * Pre-flattened `{ [id]: paths }` map for the lib's `theme.icons` field.
 * The library's `kind: 'icon'` slot looks paths up here first, falling
 * back to the built-in line glyphs (database / server / cloud / ...) for
 * unknown ids — so `customData.kind: "vercel"` renders the Vercel triangle
 * and `customData.kind: "cloud"` (or no kind at all) renders the lib's
 * generic stroked cloud as a sensible default.
 */
export const PLATFORM_ICONS: Record<string, string[]> = Object.fromEntries(
  PLATFORMS.map((p) => [p.id, p.paths]),
);


